local _b64="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local _key=90
local function _dec(s)
    
    local t={}
    for i=1,#s do
        local ch=s:sub(i,i)
        if ch~="=" then
            t[#t+1]=_b64:find(ch,1,true)-1
        end
    end
    local bytes={}
    for i=1,#t-3,4 do
        local a,b,c,d=t[i],t[i+1],(t[i+2] or 0),(t[i+3] or 0)
        local n=a*262144+b*4096+c*64+d
        -- استخرج الـ 3 bytes
        local b1=math.floor(n/65536)%256
        local b2=math.floor(n/256)%256
        local b3=n%256
        bytes[#bytes+1]=b1~_key
        -- بس حط b2 و b3 لو مش padding
        if t[i+2] then bytes[#bytes+1]=b2~_key end
        if t[i+3] then bytes[#bytes+1]=b3~_key end
    end
    
    local r=""
    local chunk=128
    for i=1,#bytes,chunk do
        local part={}
        for j=i,math.min(i+chunk-1,#bytes) do
            part[#part+1]=bytes[j]
        end
        r=r..string.char(table.unpack(part))
    end
    return r
end
